Page._content:
:root {
  --neon-bg: #050711;
  --neon-panel: rgba(10, 18, 37, 0.76);
  --neon-cyan: #25e7ff;
  --neon-pink: #ff3df2;
  --neon-yellow: #ffe65c;
  --neon-text: #d7e4f2;
  --neon-title: #f8fbff;
  --neon-muted: #94a6bd;
  --neon-border: rgba(37, 231, 255, 0.28);
}

html {
  color-scheme: dark;
}

html,
body {
  background: var(--neon-bg) !important;
}

body {
  color: var(--neon-text);
  background:
    radial-gradient(circle at 14% 12%, rgba(37, 231, 255, 0.2), transparent 28rem),
    radial-gradient(circle at 86% 8%, rgba(255, 61, 242, 0.18), transparent 30rem),
    linear-gradient(135deg, #050711 0%, #080013 48%, #090920 100%) !important;
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: -2;
  pointer-events: none;
  background:
    linear-gradient(rgba(255, 255, 255, 0.035) 50%, transparent 50%),
    linear-gradient(90deg, rgba(37, 231, 255, 0.045) 1px, transparent 1px);
  background-size: 100% 4px, 72px 72px;
  opacity: 0.55;
}

body::after {
  content: "";
  position: fixed;
  inset: 0;
  z-index: -1;
  pointer-events: none;
  background: linear-gradient(180deg, transparent 0%, rgba(5, 7, 17, 0.78) 100%);
}

.navbar,
.navbar .navbar-collapse {
  border-bottom: 1px solid rgba(37, 231, 255, 0.24);
  background: rgba(5, 7, 17, 0.72) !important;
  box-shadow: 0 0 28px rgba(37, 231, 255, 0.12);
  backdrop-filter: blur(14px);
}

.navbar .navbar-brand,
.navbar .nav-link {
  color: var(--neon-title) !important;
  text-shadow: 0 0 12px rgba(37, 231, 255, 0.28);
}

.navbar .nav-link:hover,
.navbar .navbar-brand:hover {
  color: var(--neon-cyan) !important;
}

.banner {
  position: relative;
  overflow: hidden;
}

.banner::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    linear-gradient(90deg, rgba(37, 231, 255, 0.18), transparent 28%, rgba(255, 61, 242, 0.18)),
    repeating-linear-gradient(0deg, rgba(255, 255, 255, 0.045) 0 1px, transparent 1px 5px);
  mix-blend-mode: screen;
}

.banner .h1,
.banner h1,
.banner .slogan,
.banner .subtitle {
  color: var(--neon-title) !important;
  letter-spacing: 0;
  text-shadow:
    0 0 8px rgba(37, 231, 255, 0.72),
    0 0 22px rgba(255, 61, 242, 0.42);
}

.banner .banner-text::before {
  content: "Q仔--个人博客";
  display: block;
  margin-bottom: 1rem;
  color: var(--neon-title);
  font-size: clamp(2.8rem, 7vw, 6.8rem);
  font-weight: 900;
  line-height: 1.05;
  letter-spacing: 0;
  text-shadow:
    0 0 10px rgba(37, 231, 255, 0.88),
    0 0 32px rgba(255, 61, 242, 0.52),
    4px 0 0 rgba(255, 61, 242, 0.22),
    -4px 0 0 rgba(37, 231, 255, 0.2);
}

.banner .banner-text .h2 {
  min-height: 2.2rem;
  color: var(--neon-title);
  font-size: clamp(1.05rem, 2.2vw, 1.8rem);
  text-shadow: 0 0 18px rgba(37, 231, 255, 0.48);
}

.banner h1,
.banner .h1 {
  font-weight: 800;
}

.markdown-body,
.board,
.post-content,
.post,
.archive-list,
.category-list,
.tag-cloud,
#comments {
  color: var(--neon-text);
}

.board,
.post-item,
.pagination,
.toc,
.category-list,
.tag-cloud,
.archive-list,
#comments {
  border: 1px solid var(--neon-border);
  border-radius: 14px;
  background: linear-gradient(180deg, rgba(12, 20, 42, 0.82), rgba(7, 10, 24, 0.86)) !important;
  box-shadow:
    0 18px 52px rgba(0, 0, 0, 0.36),
    inset 0 1px 0 rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(16px);
}

.post-item,
#comments {
  position: relative;
  overflow: hidden;
}

.post-item::before,
.board::before,
#comments::before {
  content: "";
  position: absolute;
  left: 18px;
  right: 18px;
  top: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--neon-cyan), var(--neon-pink), transparent);
  opacity: 0.7;
}

#comments {
  margin-top: 2rem;
  padding: 2rem;
}

#comments noscript {
  color: var(--neon-muted);
}

.comment-system {
  display: flex;
  gap: 1.5rem;
  align-items: center;
  justify-content: space-between;
}

.comment-system__eyebrow {
  margin: 0 0 0.35rem;
  color: var(--neon-cyan);
  font-size: 0.78rem;
  font-weight: 700;
  text-transform: uppercase;
}

.comment-system__title {
  margin: 0;
  color: var(--neon-title);
  font-size: 1.6rem;
  line-height: 1.2;
  text-shadow: 0 0 18px rgba(37, 231, 255, 0.28);
}

.comment-system__desc {
  margin: 0.75rem 0 0;
  color: var(--neon-muted);
}

.comment-system__action {
  display: inline-flex;
  min-height: 2.6rem;
  align-items: center;
  justify-content: center;
  padding: 0.65rem 1.05rem;
  color: #050711 !important;
  border: 1px solid rgba(37, 231, 255, 0.75);
  border-radius: 8px;
  background: linear-gradient(135deg, var(--neon-cyan), var(--neon-pink));
  box-shadow: 0 0 22px rgba(37, 231, 255, 0.28);
  font-weight: 700;
  line-height: 1;
  text-decoration: none !important;
  white-space: nowrap;
}

.comment-system__action:hover {
  filter: brightness(1.08);
}

#cusdis_thread,
.cusdis {
  color-scheme: dark;
}

@media (max-width: 767px) {
  .comment-system {
    align-items: stretch;
    flex-direction: column;
  }

  .comment-system__action {
    width: 100%;
  }
}

.post-item:hover {
  border-color: rgba(255, 61, 242, 0.45);
  box-shadow:
    0 20px 62px rgba(255, 61, 242, 0.15),
    0 0 26px rgba(37, 231, 255, 0.12);
}

a,
.post-title,
.post-title a,
.index-post-title a,
.markdown-body a {
  color: var(--neon-cyan) !important;
}

a:hover,
.post-title a:hover,
.index-post-title a:hover,
.markdown-body a:hover {
  color: var(--neon-pink) !important;
  background: rgba(255, 61, 242, 0.1);
}

h1,
h2,
h3,
h4,
h5,
h6,
.post-title,
.index-post-title,
.markdown-body h1,
.markdown-body h2,
.markdown-body h3 {
  color: var(--neon-title) !important;
}

.post-meta,
.post-meta a,
.index-post-meta,
.index-excerpt,
.archive-post time,
.text-muted {
  color: var(--neon-muted) !important;
}

.btn,
button,
.pagination .page-number,
.pagination .extend {
  border: 1px solid rgba(37, 231, 255, 0.45) !important;
  color: var(--neon-title) !important;
  background: linear-gradient(135deg, rgba(37, 231, 255, 0.12), rgba(255, 61, 242, 0.1)) !important;
  box-shadow: 0 0 18px rgba(37, 231, 255, 0.12);
}

.btn:hover,
button:hover,
.pagination .page-number:hover,
.pagination .extend:hover,
.pagination .current {
  color: #050711 !important;
  background: linear-gradient(135deg, var(--neon-cyan), var(--neon-pink)) !important;
  box-shadow: 0 0 24px rgba(255, 61, 242, 0.34);
}

blockquote {
  border-left: 3px solid var(--neon-pink) !important;
  color: var(--neon-text);
  background: rgba(255, 61, 242, 0.08) !important;
}

pre,
code,
.hljs {
  color: #d8f7ff;
  background: #070a17 !important;
}

figure.highlight,
.markdown-body pre {
  border: 1px solid rgba(37, 231, 255, 0.2);
  border-radius: 12px;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

table,
td,
th {
  border-color: rgba(37, 231, 255, 0.22) !important;
}

th {
  color: var(--neon-title);
  background: rgba(37, 231, 255, 0.08) !important;
}

#footer {
  color: var(--neon-muted);
  background: rgba(3, 5, 14, 0.88) !important;
  border-top: 1px solid rgba(37, 231, 255, 0.2);
}

#footer a {
  color: var(--neon-cyan) !important;
}

::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, var(--neon-cyan), var(--neon-pink)) !important;
}

@media (max-width: 767px) {
  .banner h1,
  .banner .h1 {
    font-size: 2.35rem !important;
  }

  .banner .banner-text::before {
    font-size: 2.65rem;
  }

  .banner .banner-text .h2 {
    padding: 0 1rem;
    font-size: 1.05rem;
  }

  .board,
  .post-item {
    border-radius: 12px;
  }
}

